  // GET /users/:id
  const matchId = pathname.match(/^\/users\/([^/]+)$/);
  if (req.method === "GET" && matchId) {
    return getUser(matchId[1]);
  }

  // GET /users?field=value
  if (req.method === "GET" && pathname === "/users") {
    return searchUsers(url);
  }

  return json({ error: "not found" }, 404);
